import React, { useState, useEffect } from 'react';

export default function Typewriter({ phrases, typeMs = 100, deleteMs = 50, pauseMs = 1200 }) {
  const [phrase, setPhrase] = useState(0);
  const [count, setCount] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const full = phrases[phrase];
    const atFull = !deleting && count === full.length;
    const atEmpty = deleting && count === 0;
    const delay = atFull ? pauseMs : deleting ? deleteMs : typeMs;

    const id = setTimeout(() => {
      if (atFull) {
        setDeleting(true);
      } else if (atEmpty) {
        setDeleting(false);
        setPhrase((p) => (p + 1) % phrases.length);
      } else {
        setCount((c) => c + (deleting ? -1 : 1));
      }
    }, delay);

    return () => clearTimeout(id);
  }, [count, deleting, phrase, phrases, typeMs, deleteMs, pauseMs]);

  return (
    <span style={{ color: '#2563eb', fontWeight: 700 }}>
      {phrases[phrase].slice(0, count)}
      <span style={{ animation: 'tw-blink 1s steps(1) infinite' }}>|</span>
      <style>{`@keyframes tw-blink { 50% { opacity: 0; } }`}</style>
    </span>
  );
}

