import { Component, Input, OnInit, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-typewriter',
  template: `<span class="tw">{{ text }}<span class="cursor">|</span></span>`,
  styles: [`
    .tw { color: #2563eb; font-weight: 700; }
    .cursor { animation: tw-blink 1s steps(1) infinite; }
    @keyframes tw-blink { 50% { opacity: 0; } }
  `],
})
export class TypewriterComponent implements OnInit, OnDestroy {
  @Input() phrases: string[] = [];
  @Input() typeMs = 100;
  @Input() deleteMs = 50;
  @Input() pauseMs = 1200;
  phrase = 0;
  count = 0;
  deleting = false;
  private timer: any = null;

  get text(): string {
    return this.phrases[this.phrase].slice(0, this.count);
  }

  step(): void {
    const full = this.phrases[this.phrase];
    const atFull = !this.deleting && this.count === full.length;
    const atEmpty = this.deleting && this.count === 0;
    const delay = atFull ? this.pauseMs : this.deleting ? this.deleteMs : this.typeMs;

    this.timer = setTimeout(() => {
      if (atFull) {
        this.deleting = true;
      } else if (atEmpty) {
        this.deleting = false;
        this.phrase = (this.phrase + 1) % this.phrases.length;
      } else {
        this.count += this.deleting ? -1 : 1;
      }
      this.step();
    }, delay);
  }

  ngOnInit(): void {
    this.step();
  }

  ngOnDestroy(): void {
    clearTimeout(this.timer);
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Typewriter Demo</h1>
      <div style="font-size: 24px;">I love <app-typewriter [phrases]="phrases"></app-typewriter></div>
    </div>
  `,
})
export class AppComponent {
  phrases = ['Angular', 'React', 'Vue', 'TypeScript'];
}

@NgModule({
  declarations: [AppComponent, TypewriterComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
